/* TLM Lesson Viewer — Vanilla JS global search
 * Fetches search-index.json on first keystroke, then filters in-memory.
 * Zero dependencies beyond the static JSON file generated by build.js.
 */
(function () {
  'use strict';

  var input   = document.getElementById('sidebar-search-input');
  var results = document.getElementById('search-results');
  if (!input || !results) return;

  var index   = null;
  var loading = false;

  function escapeHtml(str) {
    return str
      .replace(/&/g, '&amp;')
      .replace(/</g, '&lt;')
      .replace(/>/g, '&gt;')
      .replace(/"/g, '&quot;');
  }

  function highlight(text, query) {
    if (!query) return escapeHtml(text);
    var re = new RegExp('(' + query.replace(/[.*+?^${}()|[\]\\]/g, '\\$&') + ')', 'gi');
    return escapeHtml(text).replace(re, '<mark class="search-highlight">$1</mark>');
  }

  function render(matches, query) {
    if (!query) { results.innerHTML = ''; results.hidden = true; return; }
    if (!matches.length) {
      results.innerHTML = '<p class="search-empty">No results for <em>' + escapeHtml(query) + '</em></p>';
      results.hidden = false;
      return;
    }
    results.innerHTML = matches.map(function (entry) {
      var snippet = entry.snippet.slice(0, 120);
      var idx = entry.snippet.toLowerCase().indexOf(query.toLowerCase());
      if (idx > 40) snippet = '…' + entry.snippet.slice(idx - 20, idx + 100);
      return '<a class="search-result-item" href="../' + escapeHtml(entry.url) + '" role="option">' +
        '<span class="search-result-title">' + highlight(entry.title, query) + '</span>' +
        '<span class="search-result-snippet">' + highlight(snippet, query) + '</span>' +
        '</a>';
    }).join('');
    results.hidden = false;
  }

  function search(query) {
    if (!query) { render([], ''); return; }
    var q = query.toLowerCase();
    var matches = index.filter(function (entry) {
      return entry.title.toLowerCase().includes(q) || entry.body.toLowerCase().includes(q);
    }).slice(0, 8);
    render(matches, query);
  }

  function loadIndex(callback) {
    if (index) { callback(); return; }
    if (loading) return;
    loading = true;
    fetch('../assets/search-index.json')
      .then(function (r) { return r.json(); })
      .then(function (data) { index = data; loading = false; callback(); })
      .catch(function () { loading = false; render([], input.value.trim()); });
  }

  input.addEventListener('input', function () {
    var query = input.value.trim();
    if (!query) { render([], ''); return; }
    loadIndex(function () { search(query); });
  });

  /* Close results when clicking outside */
  document.addEventListener('click', function (e) {
    if (!input.contains(e.target) && !results.contains(e.target)) {
      results.hidden = true;
    }
  });

  /* Keyboard nav: Escape clears */
  input.addEventListener('keydown', function (e) {
    if (e.key === 'Escape') { input.value = ''; render([], ''); input.blur(); }
  });
})();
